const cache = new Map();

async function searchHandler(req, res) {
  const q = (req.query.q || '').toString();

  if (cache.has(q)) {
    return res.json({ ok: true, results: cache.get(q), cached: true });
  }

  const results = q ? [{ name: q, score: 1 }] : [];
  cache.set(q, results);
  return res.json({ ok: true, results, cached: false });
}

module.exports = { searchHandler };
EOF
